### 🔴 1. No Authentication or Authorization on `/users`

**Current code:**
```js
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

Any anonymous user can `GET /users` and receive a full list of user records including email addresses. This is a textbook **Broken Access Control** violation and a **GDPR/privacy** concern.

**Fix — Add JWT authentication middleware:**
```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Invalid or expired token' });
    req.user = user;
    next();
  });
}

// Apply to protected routes
app.get('/users', requireAuth, (req, res) => {
  // Also consider role-based access: only admins should see all users
  res.json(users);
});
