  const safeUsers = users.map(({ id, name }) => ({ id, name })); // omit email
  res.json(safeUsers);
});
```

If email is genuinely needed, add role-based checks:
```js
const safeUsers = users.map(u => ({
  id: u.id,
  name: u.name,
  ...(req.user.role === 'admin' && { email: u.email }),
}));
```

